function changeSubscription(userId, currentPlan, newPlan) {
    let planPrices = {
        'free': 0,
        'pro': 10,
        'enterprise': 50
    };

    if (currentPlan === newPlan) {
        return {newPlan: newPlan, chargeAmount: 0};
    }

    if (!['free', 'pro', 'enterprise'].includes(newPlan)) {
        throw new Error('Invalid plan');
    }

    let currentPrice = planPrices[currentPlan];
    let newPrice = planPrices[newPlan];

    if (currentPrice === 0 && newPrice !== 0) {
        return {newPlan: newPlan, chargeAmount: newPrice};
    } else if (currentPrice !== 0 && newPrice === 0) {
        return {newPlan: newPlan, chargeAmount: -currentPrice};
    }

    let priceDifference = Math.abs(newPrice - currentPrice);

    return {newPlan: newPlan, chargeAmount: priceDifference};
}